const body = $input.first().json.body || {};
if (!body.qc_id) { return [{ json: { valid: false, error: 'qc_id obligatorio' } }]; }
if (!body.item_id) { return [{ json: { valid: false, error: 'item_id obligatorio' } }]; }
const valid = ['pass','fail','skip','pending'];
if (!body.status || !valid.includes(body.status)) { return [{ json: { valid: false, error: 'status debe ser ' + valid.join('|') } }]; }
return [{ json: {
  valid: true,
  qc_id: body.qc_id,
  item_id: body.item_id,
  status: body.status,
  evidence_url: body.evidence_url || null,
  comment: (body.comment || '').toString().slice(0, 1000)
}}];
